const Default = () => {
    const data = useMemo(() => generateTestData({ maxLevel: args.maxLevel }), [args.maxLevel])
    return <ActivityCalendar data={data} />;
};

const ActivityLevels = () => {
    const data = useMemo(() => generateTestData({ maxLevel: args.maxLevel }), [args.maxLevel])

    return (
        <Container>
            <h1>Activity levels</h1>
            <ActivityCalendar maxLevel={2} data={data} style={{ margin: '1.5rem 0' }} />
            <p>Use the{' '}
                <code>
                    <b>maxLevel</b>
                </code>{' '}prop to control the number of activity levels. This value is zero indexed, where 0
                          represents no activity. <code>maxLevel</code>is 4 by default, so this results in 5
                          activity levels. Each activity level must be in the interval from 0 to{' '}
                <code>maxLevel</code>.
                        </p>
        </Container>
    );
};

const DateRanges = () => {
    const dataLong = useMemo(
      () =>
        generateTestData({
          maxLevel: args.maxLevel,
          interval: {
            start: new Date(2022, 5, 1),
            end: new Date(2023, 4, 31),
          },
        }),
      [args.maxLevel],
    )

    const dataMedium = useMemo(
      () =>
        generateTestData({
          maxLevel: args.maxLevel,
          interval: {
            start: new Date(2023, 2, 8),
            end: new Date(2023, 7, 1),
          },
        }),
      [args.maxLevel],
    )

    const dataShort = useMemo(
      () =>
        generateTestData({
          maxLevel: args.maxLevel,
          interval: {
            start: new Date(2023, 5, 14),
            end: new Date(2023, 6, 17),
          },
        }),
      [args.maxLevel],
    )

    return (
        <Stack>
            <ActivityCalendar
                data={dataLong}
                labels={{
                  totalCount: '{{count}} activities in 2022 & 2023',
                }} />
            <ActivityCalendar data={dataMedium} />
            <ActivityCalendar data={dataShort} />
        </Stack>
    );
};

const ColorThemes = () => {
    const data = useMemo(() => generateTestData({ maxLevel: args.maxLevel }), [args.maxLevel])

    return (
        <Container>
            <h1>Color themes</h1>
            <ActivityCalendar
                theme={{
                  light: ['hsl(0, 0%, 92%)', 'rebeccapurple'],
                  dark: ['hsl(0, 0%, 22%)', 'hsl(225,92%,77%)'],
                }}
                data={data}
                style={{ margin: '2rem 0' }} />
            <p>Use the{' '}
                <code>
                    <b>theme</b>
                </code>{' '}prop to configure the calendar colors for the light and dark{' '}
                <a href="https://developer.mozilla.org/en-US/docs/Web/CSS/color-scheme">color scheme</a>.
                          Provide all colors per scheme{' '}
                <LinkTo kind="react-activity-calendar" name="explicit-themes">explicitly
                              </LinkTo>{' '}(5 by default) or set exactly two colors (the lowest and highest intensity) to calculate a
                          single-hue scale. For explicit themes the color count must match the number of activity
                          levels, which is controlled by the{' '}
                <LinkTo kind="react-activity-calendar" name="activity-levels">
                    <code>maxLevel</code>
                </LinkTo>{' '}prop. Colors can be specified in any valid CSS format.
                        </p>
            <p>At least one scheme's colors must be set. If undefined, the default theme is used. By
                          default, the calendar selects the current system color scheme, but you can enforce a
                          specific scheme with the{' '}
                <a href="/?path=/docs/react-activity-calendar--docs">
                    <code>colorScheme</code>
                </a>{' '}prop.
                        </p>
            <Source code={exampleTheme} isDarkMode={useDarkMode()} />
        </Container>
    );
};

const ExplicitThemes = () => {
    const data = useMemo(() => generateTestData({ maxLevel: 4 }), [])

    return (
        <Container>
            <h1>Explicit theme</h1>
            <p />
            <p>See the{' '}
                <LinkTo kind="react-activity-calendar" name="color-themes">color themes
                              </LinkTo>{' '}page for details how to use the <code>theme</code>prop.
                        </p>
            <ActivityCalendar theme={explicitTheme} data={data} style={{ marginTop: '2rem' }} />
        </Container>
    );
};

const Customization = () => {
    const data = useMemo(() => generateTestData({ maxLevel: args.maxLevel }), [args.maxLevel])

    return (
        <ActivityCalendar
            blockSize={14}
            blockRadius={7}
            blockMargin={5}
            fontSize={16}
            theme={explicitTheme}
            data={data} />
    );
};

const EventHandlers = () => {
    const data = useMemo(() => generateTestData({ maxLevel: args.maxLevel }), [args.maxLevel])

    return (
        <Container>
            <h1>Event Handlers</h1>
            <p>Use the{' '}
                <code>
                    <b>renderBlock</b>
                </code>{' '}prop to attach event handlers to the SVG <code>rect</code>elements that represent
                          calendar days. Click on any block below to see it in action.
                        </p>
            <ActivityCalendar
                renderBlock={(block, activity) =>
                  cloneElement(block, {
                    onClick: () => {
                      alert(JSON.stringify(activity))
                    },
                    onMouseEnter: () => {
                      // eslint-disable-next-line no-console
                      console.log('on mouse enter')
                    },
                  })}
                data={data}
                style={{ margin: '2rem 0' }} />
            <p>Use the <code>React.cloneElement()</code>function to assign the handlers:
                        </p>
            <Source code={exampleEventHandlers} isDarkMode={useDarkMode()} />
        </Container>
    );
};

const Tooltips = () => {
    const data = useMemo(() => generateTestData({ maxLevel: args.maxLevel }), [args.maxLevel])

    return (
        <Container>
            <h1>Tooltips</h1>
            <p>Use the{' '}
                <code>
                    <b>tooltips</b>
                </code>{' '}prop to show tooltips when hovering the calendar days or the color legend. Each tooltip's
                          content is generated by a callback function, which receives either the activity data or
                          level value of the hovered element.
                        </p>
            <ActivityCalendar
                tooltips={{
                  activity: {
                    text: activity => `${activity.level} activities on ${activity.date}`,
                  },
                  colorLegend: {
                    text: level => `Activity level ${level + 1}`,
                  },
                }}
                data={data}
                style={{ margin: '2rem 0' }} />
            <p>Tooltips no longer depend on external libraries and are now integrated directly into this
                          package. Thanks to code-splitting, tooltips only affect your bundle size when you use
                          them. Tooltips are implemented using the{' '}
                <a href="https://floating-ui.com/">Floating UI</a>library as a “headless” component,
                          meaning they come <b>without predefined styles</b>. This gives you full control over the
                          appearance:
                        </p>
            <ul>
                <li>Import the default styles provided by this package, <b>or</b>
                </li>
                <li>Add your own custom CSS.</li>
            </ul>
            <Source
                code="import 'react-activity-calendar/tooltips.css';"
                isDarkMode={useDarkMode()} />
            <Source
                code={`/* Adapt to your needs */\n${exampleTooltipsCSS}`}
                isDarkMode={useDarkMode()} />
            <h2>Tooltip configuration</h2>
            <p>You can configure the tooltips with the following optional settings:</p>
            <ul>
                <li>
                    <a href="https://floating-ui.com/docs/useFloating#placement">placement</a>of the
                                tooltip
                              </li>
                <li>
                    <a href="https://floating-ui.com/docs/offset#options">offset</a>to the element in
                                pixels (4 by default)
                              </li>
                <li>the cursor “<a href="https://floating-ui.com/docs/useHover#restms">rest time</a>” in
                                milliseconds before opening a tooltip (150ms by default)
                              </li>
                <li>
                    <a
                        href="https://floating-ui.com/docs/useTransition#usetransitionstyles-props">transition styles
                                    </a>{' '}to fine-tune CSS animations
                              </li>
                <li>whether to draw an arrow (false by default)</li>
            </ul>
            <Source code={exampleTooltipsConfig} isDarkMode={useDarkMode()} />
            <ActivityCalendar
                data={data}
                tooltips={{
                  activity: {
                    text: activity => `${activity.level} activities on ${activity.date}`,
                    placement: 'right',
                    offset: 8,
                    transitionStyles: {
                      duration: 100,
                      common: { fontFamily: 'monospace' },
                    },
                    hoverRestMs: 300,
                    withArrow: true,
                  },
                }}
                style={{ margin: '2rem 0' }} />
        </Container>
    );
};

const WithoutLabels = () => {
    const data = useMemo(() => generateTestData({ maxLevel: args.maxLevel }), [args.maxLevel])

    return (
        <ActivityCalendar
            showMonthLabels={false}
            showColorLegend={false}
            showTotalCount={false}
            data={data} />
    );
};

const WeekdayLabels = () => {
    const data = useMemo(() => generateTestData({ maxLevel: args.maxLevel }), [args.maxLevel])

    return (
        <Stack>
            <div>
                <StackHeading code="true">Show every second weekday (default)</StackHeading>
                <ActivityCalendar showWeekdayLabels data={data} />
            </div>
            <div>
                <StackHeading code="['mon', 'fri']">Show specific days</StackHeading>
                <ActivityCalendar data={data} showWeekdayLabels={['mon', 'fri']} />
            </div>
            <div>
                <StackHeading code="['sun', 'mon', 'tue', 'wed', 'thu', 'fri', 'sat']">Show every day
                              </StackHeading>
                <ActivityCalendar
                    data={data}
                    showWeekdayLabels={['sun', 'mon', 'tue', 'wed', 'thu', 'fri', 'sat']} />
            </div>
        </Stack>
    );
};

const LocalizedLabels = () => {
    const data = useMemo(() => generateTestData({ maxLevel: args.maxLevel }), [args.maxLevel])

    return (
        <Container>
            <h1>Localization</h1>
            <p>Example in German:</p>
            <ActivityCalendar
                showWeekdayLabels
                labels={{
                  months: ['Jan', 'Feb', 'Mär', 'Apr', 'Mai', 'Jun', 'Jul', 'Aug', 'Sep', 'Okt', 'Nov', 'Dez'],
                  weekdays: ['So', 'Mo', 'Di', 'Mi', 'Do', 'Fr', 'Sa'],
                  totalCount: '{{count}} Aktivitäten in {{year}}',
                  legend: {
                    less: 'Weniger',
                    more: 'Mehr',
                  },
                }}
                data={data}
                style={{ margin: '2rem 0' }} />
            <Source code={exampleLabelsShape} isDarkMode={useDarkMode()} />
        </Container>
    );
};

const MondayAsWeekStart = () => {
    const data = useMemo(() => generateTestData({ maxLevel: args.maxLevel }), [args.maxLevel])
    return <ActivityCalendar weekStart={1} data={data} />;
};

const NarrowScreens = () => {
    const data = useMemo(() => generateTestData({ maxLevel: args.maxLevel }), [args.maxLevel])

    return (
        <div style={{ width: 480, maxWidth: '100%', border: 'dashed 1px #929292' }}>
            <ActivityCalendar data={data} />
        </div>
    );
};

const ContainerRef = () => {
    const data = useMemo(() => generateTestData({ maxLevel: args.maxLevel }), [args.maxLevel])
    const calendarRef = useRef<HTMLElement>(null)

    useEffect(() => {
      // eslint-disable-next-line no-console
      console.log('calendar ref', calendarRef)
    }, [calendarRef])

    return (
        <>
            <ActivityCalendar data={data} ref={calendarRef} />
            <br />
            <p>Check the JavaScript console to see the ref logged.</p>
        </>
    );
};

